import React, { useState, useEffect } from "react";
import styles from "../styles/TaskForm.module.css";

const TaskForm = ({ onTaskCreated, onTaskUpdated, editingTask, onCancelEdit, categories }) => {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    deadline: "",
    categoryId: "",
  });
  const [error, setError] = useState("");

  useEffect(() => {
    if (editingTask) {
      let formattedDeadline = "";
      if (editingTask.deadline) {
        formattedDeadline = editingTask.deadline.substring(0, 16);
      }
      setFormData({
        title: editingTask.title || "",
        description: editingTask.description || "",
        deadline: formattedDeadline,
        categoryId: editingTask.categoryId || "",
      });
      setError("");
    } else {
      setFormData({ title: "", description: "", deadline: "", categoryId: "" });
    }
  }, [editingTask]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!formData.title.trim()) {
      setError("El título no puede estar vacío.");
      return;
    }
    if (!formData.categoryId) {
      setError("Selecciona una lista/categoría.");
      return;
    }

    const submitData = { ...formData };
    if (submitData.deadline) {
      if (submitData.deadline.length === 16) submitData.deadline += ":00";
    } else {
      submitData.deadline = null;
    }

    try {
      if (editingTask) await onTaskUpdated(editingTask.id, submitData);
      else await onTaskCreated(submitData);
    } catch (err) {
      setError("Error al guardar la tarea.");
    }
  };

  return (
    <div className={styles.overlay}>
      <div className={styles.form}>
        <div className={styles.header}>
          <h3>{editingTask ? "Detalles" : "Nueva Tarea"}</h3>
          <button className={styles.closeBtn} onClick={onCancelEdit}>OK</button>
        </div>

        {error && <div className={styles.error}>{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className={styles.inputGroup}>
            <input
              type="text"
              placeholder="Título"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              className={styles.input}
              autoFocus
            />
          </div>
          <div className={styles.inputGroup}>
            <textarea
              placeholder="Notas"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              className={styles.textarea}
            />
          </div>

          <div className={styles.row}>
            <div className={styles.half}>
              <label className={styles.label}>Fecha Límite</label>
              <input
                type="datetime-local"
                value={formData.deadline}
                onChange={(e) => setFormData({ ...formData, deadline: e.target.value })}
                className={styles.datetime}
              />
            </div>
            <div className={styles.half}>
              <label className={styles.label}>Lista</label>
              <select
                value={formData.categoryId}
                onChange={(e) => setFormData({ ...formData, categoryId: e.target.value })}
                className={styles.select}
              >
                <option value="">Ninguna</option>
                {categories.map((cat) => (
                  <option key={cat.id} value={cat.id}>
                    {cat.title}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <button type="submit" className={styles.submitBtn}>
            {editingTask ? "Guardar" : "Añadir"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default TaskForm;
